const input = $items('Set Input Defaults')[0].json;
const promptText = input.prompt_text || '';
const projectName = input.project_name || 'default-project';

// Sanitize Lucene special characters from the prompt (Pitfall 2, T-3-06)
// Strip: + - ! ( ) { } [ ] ^ " ~ * ? : \ /
let cleanedQuery = promptText.replace(/[+\-!(){}\[\]^"~*?:\\/]/g, ' ').trim();
// Collapse multiple spaces
cleanedQuery = cleanedQuery.replace(/\s+/g, ' ').trim();
// Fallback to match-all if empty after sanitization
if (!cleanedQuery) {
  cleanedQuery = '*';
}

// Deterministic full-text search Cypher — NOT LLM-generated (D-06)
const cypher = "CALL db.index.fulltext.queryNodes('knowledge_note_search', $query) YIELD node, score WHERE node.project = $project AND node.graph = $graph RETURN node.noteId AS noteId, node.title AS title, node.content AS content, score ORDER BY score DESC LIMIT 5";

const neo4jBody = {
  statements: [
    {
      statement: cypher,
      parameters: {
        query: cleanedQuery,
        project: projectName,
        graph: 'SpecGraph'
      }
    }
  ]
};

return [{ json: { ...input, cypherUsed: cypher, cleanedQuery: cleanedQuery, neo4jBody: neo4jBody } }];

const input = $items('Build Full-Text Cypher')[0].json;
const promptText = input.prompt_text || '';
const projectName = input.project_name || 'default-project';

// Extract results from Neo4j response
const results = $json.results;
const data = (results && results[0] && results[0].data) ? results[0].data : [];
const matchCount = data.length;

let answerPrompt;
if (matchCount === 0) {
  answerPrompt = "No matching knowledge notes found for project '" + projectName + "'. Reply: 'No matching knowledge notes found for this project.'";
} else {
  // Build notes section from top-5 results (D-05)
  const top5 = data.slice(0, 5);
  const noteLines = top5.map((row, idx) => {
    const cols = row.row || [];
    // Columns: noteId(0), title(1), content(2), score(3)
    const title = cols[1] || '';
    const content = cols[2] || '';
    return (idx + 1) + '. [' + title + ']: ' + content;
  }).join('\n');

  answerPrompt = [
    'You are an architectural knowledge assistant. Answer the question using ONLY the provided notes.',
    'If the notes do not contain enough information, say so.',
    '',
    'Question: ' + promptText,
    '',
    'Notes:',
    noteLines,
    '',
    'Answer concisely in 1-3 sentences.'
  ].join('\n');
}

return [{ json: { ...input, matchCount: matchCount, answerPrompt: answerPrompt } }];

const input = $items('Build Answer Prompt')[0].json;
const raw = $json.response !== undefined ? $json.response : '';
let answer = typeof raw === 'string' ? raw.trim() : String(raw).trim();
if (!answer) {
  answer = 'No answer could be generated.';
}
return [{ json: { ...input, answer: answer } }];
